#!/usr/bin/env node
/**
 * Read bootstrap JSON (stdin or --file) and print selected fields for Cloud Run / GitHub wiring.
 *
 * Usage:
 *   aws secretsmanager get-secret-value ... | node extract-bootstrap-fields.mjs --json
 *   node extract-bootstrap-fields.mjs --file payload.json --field supabase_url
 *
 * Env: REBASE_DATABASE_URL_MODE=direct|pooler (default pooler)
 *      REBASE_SUPABASE_PROJECT_REGION (default us-east-2 when not in JSON)
 */
import { readFileSync } from 'node:fs';

function trim(s) {
  return (s ?? '').trim();
}

function die(msg) {
  console.error(`[extract-bootstrap-fields] ${msg}`);
  process.exit(1);
}

function parsePayload(raw) {
  let data;
  try {
    data = JSON.parse(raw);
  } catch {
    die('bootstrap JSON is not valid JSON');
  }
  if (!data || typeof data !== 'object') {
    die('bootstrap JSON must be an object');
  }
  const ref = trim(data.supabase_project_ref ?? data.supabaseProjectRef);
  const password = trim(data.database_password ?? data.databasePassword);
  const supabaseUrl = trim(data.supabase_url ?? data.supabaseUrl);
  const anonKey = trim(data.supabase_anon_key ?? data.supabaseAnonKey);
  if (!ref) die('missing supabase_project_ref');
  if (!password) die('missing database_password');
  if (!supabaseUrl) die('missing supabase_url');
  if (!anonKey) die('missing supabase_anon_key');
  const region =
    trim(data.supabase_project_region ?? data.supabaseProjectRegion) ||
    trim(process.env.REBASE_SUPABASE_PROJECT_REGION) ||
    'us-east-2';
  return { ref, password, supabaseUrl, anonKey, region };
}

function buildDatabaseUrl({ ref, password, mode, region }) {
  const enc = encodeURIComponent(password);
  if (mode === 'direct') {
    return `postgresql://postgres:${enc}@db.${ref}.supabase.co:5432/postgres`;
  }
  if (mode === 'pooler') {
    return `postgresql://postgres.${ref}:${enc}@aws-0-${region}.pooler.supabase.com:6543/postgres`;
  }
  die('REBASE_DATABASE_URL_MODE must be direct or pooler');
}

const args = process.argv.slice(2);
const fileIdx = args.indexOf('--file');
const jsonMode = args.includes('--json');
const fieldIdx = args.indexOf('--field');
const fieldName = fieldIdx >= 0 ? trim(args[fieldIdx + 1]) : '';

let raw = '';
if (fileIdx >= 0) {
  const path = args[fileIdx + 1];
  if (!path) die('--file requires a path');
  raw = readFileSync(path, 'utf8');
} else {
  raw = readFileSync(0, 'utf8');
}

const mode = trim(process.env.REBASE_DATABASE_URL_MODE).toLowerCase() || 'pooler';
const payload = parsePayload(raw);
const databaseUrl = buildDatabaseUrl({ ...payload, mode });

const doc = {
  supabase_project_ref: payload.ref,
  supabase_url: payload.supabaseUrl,
  supabase_anon_key: payload.anonKey,
  database_url: databaseUrl,
};

if (jsonMode) {
  process.stdout.write(`${JSON.stringify(doc)}\n`);
} else if (fieldName) {
  const value = doc[fieldName];
  if (value === undefined) {
    die(`unknown field ${fieldName}`);
  }
  process.stdout.write(`${value}`);
} else {
  die('pass --json or --field <name>');
}

#!/usr/bin/env bash
# Per-repo GCP + GitHub Actions wiring for Cloud Run on main (production environment).
#
# Prerequisites:
#   - Platform: scripts/gcp/setup-platform-cloudrun.sh on AgentOS host (once)
#   - scripts/rebase-platform.env in workspace (written by provisioner product bootstrap)
#   - gcloud auth login, gh auth login (repo admin)
#   - AWS bootstrap secret in Secrets Manager (Supabase project bootstrap)
#
# Usage: single argument, workspace root. Idempotent. Wire only (no deploy smoke).
set -euo pipefail

INPUT_JSON='input.json'
PLATFORM_ENV='scripts/rebase-platform.env'
REBASE_GCP_AR_REPO="${REBASE_GCP_AR_REPO:-rebase-apps}"
REBASE_GCP_WIF_POOL="${REBASE_GCP_WIF_POOL:-rebase-pool}"
REBASE_GCP_WIF_PROVIDER="${REBASE_GCP_WIF_PROVIDER:-github}"
REBASE_GCP_DEPLOY_SA="${REBASE_GCP_DEPLOY_SA:-rebase-deploy}"
REBASE_GITHUB_ORG="${REBASE_GITHUB_ORG:-trilogy-group}"
GITHUB_ENVIRONMENT='production'

usage() {
  printf '%s\n' "usage: ${0##*/} <workspace-root>" >&2
  exit 2
}

err() {
  printf '%s\n' "$1" >&2
}

log() {
  printf '[cloudrun] %s\n' "$*"
}

if [[ $# -ne 1 ]]; then
  usage
fi

WORKSPACE="$(cd "$1" && pwd)"
INPUT_PATH="${WORKSPACE}/${INPUT_JSON}"
PLATFORM_PATH="${WORKSPACE}/${PLATFORM_ENV}"
WIRE_SCRIPT="${WORKSPACE}/scripts/bootstrap/wire-cloudrun-supabase.sh"

if [[ ! -f "$INPUT_PATH" ]]; then
  err "${0##*/}: missing ${INPUT_PATH}"
  exit 1
fi

if [[ ! -f "$PLATFORM_PATH" ]]; then
  err "${0##*/}: missing ${PLATFORM_PATH} (provisioner must inject GCP platform env)"
  exit 1
fi

if [[ ! -f "$WIRE_SCRIPT" ]]; then
  err "${0##*/}: missing ${WIRE_SCRIPT}"
  exit 1
fi

# shellcheck disable=SC1090
source "$PLATFORM_PATH"

: "${REBASE_GCP_PROJECT_ID:?REBASE_GCP_PROJECT_ID missing in ${PLATFORM_ENV}}"
: "${REBASE_GCP_REGION:?REBASE_GCP_REGION missing in ${PLATFORM_ENV}}"
: "${REBASE_GCP_WORKLOAD_IDENTITY_PROVIDER:?REBASE_GCP_WORKLOAD_IDENTITY_PROVIDER missing in ${PLATFORM_ENV}}"
: "${REBASE_GCP_SERVICE_ACCOUNT:?REBASE_GCP_SERVICE_ACCOUNT missing in ${PLATFORM_ENV}}"

command -v gcloud >/dev/null 2>&1 || { err "gcloud not found"; exit 1; }
command -v gh >/dev/null 2>&1 || { err "gh not found"; exit 1; }
command -v jq >/dev/null 2>&1 || { err "jq not found"; exit 1; }
command -v aws >/dev/null 2>&1 || { err "aws not found"; exit 1; }

gcloud auth list --filter=status:ACTIVE --format='value(account)' 2>/dev/null | grep -q . \
  || { err "gcloud not authenticated — run: gcloud auth login"; exit 1; }
gh auth status -h github.com >/dev/null 2>&1 || { err "gh not logged in to github.com"; exit 1; }

eval "$(
  INPUT_PATH="$INPUT_PATH" node -e "
const fs = require('fs');
const sh = (s) => \"'\" + String(s).replace(/'/g, \"'\\\\''\") + \"'\";
const j = JSON.parse(fs.readFileSync(process.env.INPUT_PATH, 'utf8'));
const projectName = j.project_name;
const repo = j.target_repo_url;
if (typeof projectName !== 'string' || projectName.trim().length === 0) {
  process.stderr.write('project_name must be a non-empty string in input.json\\n');
  process.exit(1);
}
if (typeof repo !== 'string' || repo.trim().length === 0) {
  process.stderr.write('target_repo_url must be a non-empty string in input.json\\n');
  process.exit(1);
}
const pn = projectName.trim();
const dnsPrefix = pn
  .toLowerCase()
  .replace(/[._]+/g, '-')
  .replace(/[^a-z0-9-]/g, '')
  .replace(/-+/g, '-')
  .replace(/^-+|-+$/g, '');
if (dnsPrefix.length === 0 || dnsPrefix.length > 63) {
  process.stderr.write('project_name must yield a non-empty DNS prefix <= 63 chars.\\n');
  process.exit(1);
}
let owner = '';
let name = '';
const u = repo.trim();
const m = u.match(/github\\.com[:\\/]([^/]+)\\/([^/.]+)/i);
if (m) {
  owner = m[1];
  name = m[2].replace(/\\.git\$/, '');
} else {
  process.stderr.write('target_repo_url must be a github.com URL\\n');
  process.exit(1);
}
process.stdout.write('PROJECT_NAME=' + sh(pn) + '\\n');
process.stdout.write('TARGET_REPO_URL=' + sh(u) + '\\n');
process.stdout.write('DNS_PREFIX=' + sh(dnsPrefix) + '\\n');
process.stdout.write('GITHUB_OWNER=' + sh(owner) + '\\n');
process.stdout.write('GITHUB_REPO=' + sh(name) + '\\n');
process.stdout.write('GCP_SERVICE_NAME=' + sh(dnsPrefix) + '\\n');
"
)"

if [[ "$GITHUB_OWNER" != "$REBASE_GITHUB_ORG" ]]; then
  err "repo owner ${GITHUB_OWNER} is not ${REBASE_GITHUB_ORG}; WIF provider trusts ${REBASE_GITHUB_ORG} only"
  exit 1
fi

principal_set() {
  local project_number
  project_number="$(gcloud projects describe "$REBASE_GCP_PROJECT_ID" --format='value(projectNumber)')"
  printf 'principalSet://iam.googleapis.com/projects/%s/locations/global/workloadIdentityPools/%s/attribute.repository/%s/%s' \
    "$project_number" "$REBASE_GCP_WIF_POOL" "$GITHUB_OWNER" "$GITHUB_REPO"
}

log "project ${REBASE_GCP_PROJECT_ID} service ${GCP_SERVICE_NAME}"
gcloud config set project "$REBASE_GCP_PROJECT_ID" >/dev/null

principal="$(principal_set)"
log "WIF binding for ${GITHUB_OWNER}/${GITHUB_REPO}"
gcloud iam service-accounts add-iam-policy-binding "$REBASE_GCP_SERVICE_ACCOUNT" \
  --project="$REBASE_GCP_PROJECT_ID" \
  --role="roles/iam.workloadIdentityUser" \
  --member="$principal" \
  --condition=None >/dev/null

export WORKSPACE
export GCP_SERVICE_NAME DNS_PREFIX GITHUB_OWNER GITHUB_REPO GITHUB_ENVIRONMENT
export REBASE_GCP_AR_REPO REBASE_GCP_WIF_POOL REBASE_GCP_WIF_PROVIDER REBASE_GCP_DEPLOY_SA
bash "$WIRE_SCRIPT"

log "done (wire only — deploy on push to main via deploy-cloudrun.yml)"

